import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"82. Travelling And Relocation Allowance","description":"","frontmatter":{"title":"82. Travelling And Relocation Allowance","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","allowances","vehicle"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/allowances/82-travelling-and-relocation-allowance.md","filePath":"ebas/mental-health/rpn-pen-mho/allowances/82-travelling-and-relocation-allowance.md"}'),l={name:"ebas/mental-health/rpn-pen-mho/allowances/82-travelling-and-relocation-allowance.md"};function r(s,e,i,c,h,m){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_82-travelling-and-relocation-allowance" tabindex="-1">82. Travelling And Relocation Allowance <a class="header-anchor" href="#_82-travelling-and-relocation-allowance" aria-label="Permalink to &quot;82. Travelling And Relocation Allowance&quot;">​</a></h1><p>This clause concerns payment only and is not intended to exclude the requirements of <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/18-consultation.html">clause 18</a> (Consultation) or 20 (Redundancy and Associated Entitlements) or create a new right to be directed to work at another location.</p><p><strong>82.1</strong> In this clause Base Employment Campus means a Campus of the Employer at which the Employee ordinarily starts and finishes work.</p><p><strong>82.2</strong> Where an Employee is required by the Employer to temporarily relocate from their Base Employment Campus to another Campus during a shift, the Employee will be paid the vehicle allowance at <a href="/eba/ebas/mental-health/common-terms/allowances/34-vehicle-allowance.html">clause 34</a> above.</p><p><strong>82.3</strong> For the avoidance of doubt, the travel will occur within paid time.</p><p><strong>82.4</strong> Where an Employee is required by the Employer to temporarily relocate from their Base Employment Campus to another Campus prior to a shift, the Employee will:</p><p><strong>(a)</strong> be reimbursed for additional traveling cost to the Employee (where applicable) excluding time spent travelling (which is addressed at (b) below); and</p><p><strong>(b)</strong> where travel time increases by 15 minutes or greater (to and return) be paid an allowance equal to the Employee&#39;s ordinary rate for the additional time spent when compared to the Employee&#39;s travel time to the Base Employment Campus. Nothing in this subclause 82.4 prevents an Employer requiring the travel to occur within the rostered shift.</p><p><strong>82.5</strong> Where an Employee is required by the Employer to permanently relocate from their Base Employment Campus to another Campus as a result of redundancy, the Employee will be reimbursed for additional travel costs (where applicable) in accordance with <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/20-redundancy-and-associated-entitlements.html">clause 20.7</a> of this Agreement (Relocation).</p><p><strong>82.6</strong> For the avoidance of doubt, nothing in this clause limits the obligations regarding redundancy contained at <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/20-redundancy-and-associated-entitlements.html">clause 20</a> of this Agreement.</p><p><strong>82.7</strong> Where an Employee&#39;s position is required by the Employer to permanently relocate from their Base Employment Campus to another Campus and the Employee&#39;s position is not redundant, the Employee will be reimbursed for additional travel costs (where applicable) in accordance with <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/20-redundancy-and-associated-entitlements.html">clause 20.7</a>(b)-20.7(f) of this Agreement. For the avoidance of doubt, where this is a result of Major Change, the terms of <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/18-consultation.html">clause 18</a> will apply, save that the Employer will not be required to take additional steps to mitigate or avert the cost of the relocation.</p><p><strong>82.8</strong> This clause does not apply to:</p><p><strong>(a)</strong> an Employee whose role goes across campuses.</p><p><strong>(b)</strong> Employees who genuinely choose to work across different campuses and it is not a requirement of the Employer, such as where an Employee elects to pick up an additional shift/s on another Campus on a permanent or ad hoc basis;</p><p><strong>(c)</strong> Casuals.</p>',15)])])}const u=t(l,[["render",r]]);export{d as __pageData,u as default};
